macros.command:
const target = await game.getTargetToken();
if (!target) { await game.notify('Выбери цель (кнопка «Цель» на жетоне).'); return; }
const result = await game.roll('2d6+3');
await game.chat(result.content);
if (result.total) await game.applyDamage(target.id, result.total);

const token = await game.getSelectedToken() ?? await game.getTargetToken();
if (!token) { await game.notify('Выбери жетон.'); return; }
const result = await game.roll('2d8+5');
await game.chat(result.content);
if (result.total) await game.applyHealing(token.id, result.total);

const target = await game.getTargetToken();
if (!target) { await game.notify('Выбери цель.'); return; }
await game.applyCondition(target.id, 'frightened', 1);
await game.chat(`На «${target.label}» наложено Frightened 1.`);

const token = await game.getSelectedToken();
if (!token) { await game.notify('Выбери жетон.'); return; }
await game.removeCondition(token.id, 'frightened');
await game.chat(`С «${token.label}» снято Frightened.`);
